// Get the upload URL from previous node
const uploadUrl = $input.item.json.data;

// Get the binary file data from Download APK node
const downloadNode = $workflow.getNode('Download APK');
const downloadData = $workflow.getNodeExecutionData(downloadNode.name, 0, 0);
const binaryData = downloadData.binary.data;

// Pass both forward
return {
  json: {
    uploadUrl: uploadUrl,
    fileName: $('Webhook').item.json.body.file
  },
  binary: {
    data: binaryData
  }
};

const filePath = $('Webhook').item.json.body.file;
const fileName = filePath.split('/').pop();
const results = $json.data.attributes.stats;
const scans = $json.data.attributes.results;

const malicious = results.malicious || 0;
const suspicious = results.suspicious || 0;
const totalDetections = malicious + suspicious;

const reputableEngines = [
  'Kaspersky', 'ESET-NOD32', 'Bitdefender', 'Microsoft', 
  'Google', 'Sophos', 'TrendMicro', 'McAfee', 'Avast'
];

let hasReputableDetection = false;
let detectionTypes = [];

for (const [engine, result] of Object.entries(scans)) {
  if (result.category === 'malicious' || result.category === 'suspicious') {
    const detectionName = result.result || '';
    detectionTypes.push(`${engine}: ${detectionName}`);

    if (reputableEngines.includes(engine)) {
      if (!detectionName.toLowerCase().includes('pup') && 
          !detectionName.toLowerCase().includes('pua')) {
        hasReputableDetection = true;
      }
    }
  }
}

let status = 'safe';
let reason = '';

if (hasReputableDetection) {
  status = 'unsafe';
  reason = 'reputable engine flagged non-pup threat';
} else if (totalDetections > 5) {
  status = 'unsafe';
  reason = `${totalDetections} detections total`;
} else if (totalDetections >= 1 && totalDetections <= 3) {
  status = 'safe';
  reason = 'low detection count from minor engines';
} else if (totalDetections === 0) {
  status = 'safe';
  reason = 'no detections';
} else {
  status = 'review';
  reason = `${totalDetections} detections - manual check recommended`;
}

return {
  fileName,
  status,
  reason,
  totalDetections,
  detectionTypes: detectionTypes.slice(0, 5),
  vtLink: $json.data.links.self.replace('/api/v3/analyses/', '/gui/file/')
};

const staticData = $getWorkflowStaticData('global');

// Get current online status safely
const isOnline = $json.online === true;
const currentVersion = $json.version?.name_raw || 'Unknown';

// Get last known state (default to online to prevent first-run spam)
const lastStateWasOnline = staticData.lastStateWasOnline !== undefined ? staticData.lastStateWasOnline : true;

let shouldPing = false;

// TRIGGER: Only if it WAS offline and is NOW online
if (isOnline && !lastStateWasOnline) {
  shouldPing = true;
}

// PERSIST: Always update the state for the next run
staticData.lastStateWasOnline = isOnline;

return {
  shouldPing,
  isOnline,
  version: currentVersion,
  previous_state: lastStateWasOnline ? 'online' : 'offline'
};

