const stats = items[0].json.attributes.last_analysis_stats;
const results = items[0].json.attributes.last_analysis_results;
const reputableEngines = ['Kaspersky', 'Bitdefender', 'Microsoft', 'ESET', 'Sophos', 'Symantec'];

let maliciousCount = stats.malicious;
let verdict = "safe";
let reasons = [];

// 1. Hard fail if more than 5 detections
if (maliciousCount > 5) {
  verdict = "unsafe";
  reasons.push(`High detection count: ${maliciousCount}`);
}

// 2. Nuanced check for 1-5 detections
if (verdict === "safe" && maliciousCount > 0) {
  let seriousThreats = 0;

  for (const engine in results) {
    const scan = results[engine];
    if (scan.category === 'malicious') {
      const label = scan.result.toLowerCase();
      const isPUP = label.includes('pup') || label.includes('pua') || label.includes('grayware');
      const isReputable = reputableEngines.includes(engine);

      if (!isPUP) {
        if (isReputable) {
          seriousThreats += 1;
          reasons.push(`${engine} detected: ${scan.result}`);
        }
      }
    }
  }

  if (seriousThreats > 0) {
    verdict = "unsafe";
  }
}

return [{ json: { verdict, maliciousCount, reasons } }];
